@app.route('/oauth/token/introspect', methods=['POST'])
def introspect_token():
    token = request.form.get('token') or request.json.get('token')
    
    if not token:
        return jsonify({'active': False}), 400
    
    token_info = validate_token(token)
    
    if token_info['valid']:
        return jsonify({
            'active': True,
            'client_id': token_info['client_id'],
            'user_id': token_info['user_id'],
            'scope': token_info['scope'],
            'exp': token_info['expires_at']
        })
    
    return jsonify({'active': False})

@app.route('/oauth/token/revoke', methods=['POST'])
@require_oauth()
def revoke_token():
    token = request.form.get('token') or request.json.get('token')
    
    if not token:
        return jsonify({'error': 'Token parameter is required'}), 400
    
    db = get_db()
    db.execute('UPDATE access_tokens SET revoked = 1 WHERE token = ?', (token,))
    db.commit()
    db.close()
    
    return jsonify({'message': 'Token revoked successfully'})

@app.route('/admin/tokens', methods=['POST'])
def create_token():
    data = request.get_json()
    
    client_id = data.get('client_id')
    user_id = data.get('user_id')
    scope = data.get('scope', 'read')
    expires_in = data.get('expires_in', 3600)
    
    if not client_id:
        return jsonify({'error': 'client_id is required'}), 400
    
    token = secrets.token_urlsafe(32)
    expires_at = datetime.utcnow().timestamp() + expires_in
    expires_at_str = datetime.fromtimestamp(expires_at).strftime('%Y-%m-%d %H:%M:%S')
    
    db = get_db()
    db.execute(
        '''
        INSERT INTO access_tokens (token, client_id, user_id, scope, expires_at)
        VALUES (?, ?, ?, ?, ?)
        ''',
        (token, client_id, user_id, scope, expires_at_str)
    )
    db.commit()
    db.close()
    
    return jsonify({
        'access_token': token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scope': scope
    }), 201

@app.route('/admin/tokens', methods=['GET'])
def list_tokens():
    db = get_db()
    cursor = db.execute(
        'SELECT token, client_id, user_id, scope, expires_at, revoked FROM access_tokens'
    )
    tokens = cursor.fetchall()
    db.close()
    
    return jsonify({
        'tokens': [dict(token) for token in tokens]
    })

